@app.route("/admin/login", methods=["GET","POST"])
def admin_login():
    error = ""
    if request.method == "POST":
        u = request.form.get("username",""); p = request.form.get("password","")
        conn = get_db()
        row = conn.execute("SELECT * FROM admins WHERE username=? AND active=1", (u,)).fetchone()
        if row and row["password_hash"] == _hash_password(p):
            # Track login
            conn.execute("UPDATE admins SET last_login=?, login_count=COALESCE(login_count,0)+1 WHERE username=?",
                         (int(time.time()), u))
            conn.commit()
            conn.close()
            session.permanent = True
            role = row["role"]
            # Reseller → panel reseller
            if role == "reseller":
                reseller_id = row["reseller_id"] or u
                session["reseller_logged"] = True
                session["reseller_id"]     = reseller_id
                add_log("OK","RESELLER",f"Login reseller via admin: {u}")
                return redirect("/reseller_panel")
            session["admin_logged"] = True
            session["admin_user"]   = row["username"]
            session["admin_role"]   = role
            add_log("OK","ADMIN",f"Login admin: {u}")
            return redirect("/admin")
        conn.close()
        error = "Identifiants incorrects ou compte désactivé"
    expired = request.args.get("expired", "")
    next_page = request.args.get("next", "")
    extra_msg = ""
    if next_page == "reseller":
        extra_msg = "Connexion Panel Revendeur — utilise ton accès revendeur."
    return render_template_string(LOGIN_HTML, error=error or extra_msg, expired=expired)

@app.route("/admin/logout")
def admin_logout():
    session.clear(); return redirect("/admin/login")

