RESELLER_PLANS_SERVER = {
    "starter":  {"name": "🥉 Starter",  "price": 19.99, "credits": 20,  "discount": 15, "max_keys": 50},
    "business": {"name": "🥈 Business", "price": 49.99, "credits": 60,  "discount": 25, "max_keys": 200},
    "elite":    {"name": "🥇 Elite",    "price": 99.99, "credits": 150, "discount": 40, "max_keys": 999},
}
LICENSE_PRICES_SERVER = {"NORMAL": 4.99, "PRO": 9.99}


def _init_reseller_db():
    conn = get_db()
    conn.executescript("""
    CREATE TABLE IF NOT EXISTS resellers (
        id           INTEGER PRIMARY KEY AUTOINCREMENT,
        discord_id   TEXT UNIQUE NOT NULL,
        discord_tag  TEXT,
        plan         TEXT NOT NULL DEFAULT 'starter',
        credits      REAL NOT NULL DEFAULT 0,
        status       TEXT NOT NULL DEFAULT 'pending',
        keys_generated INTEGER DEFAULT 0,
        keys_used    INTEGER DEFAULT 0,
        sold_normal  INTEGER DEFAULT 0,
        sold_pro     INTEGER DEFAULT 0,
        total_spent  REAL DEFAULT 0,
        total_revenue REAL DEFAULT 0,
        joined_at    INTEGER,
        approved_by  TEXT,
        note         TEXT
    );
    CREATE TABLE IF NOT EXISTS reseller_keys (
        id           INTEGER PRIMARY KEY AUTOINCREMENT,
        reseller_id  TEXT NOT NULL,
        license_key  TEXT NOT NULL,
        plan         TEXT NOT NULL,
        cost         REAL NOT NULL,
        status       TEXT DEFAULT 'unused',
        used_at      INTEGER,
        created_at   INTEGER
    );
    CREATE TABLE IF NOT EXISTS reseller_transactions (
        id           INTEGER PRIMARY KEY AUTOINCREMENT,
        reseller_id  TEXT NOT NULL,
        type         TEXT NOT NULL,
        amount       REAL,
        credits_delta REAL,
        note         TEXT,
        admin        TEXT,
        created_at   INTEGER
    );
    """)
    conn.commit(); conn.close()


try:
    _init_reseller_db()
    print("[OK] Reseller DB initialisée")
except Exception as _e:
    print(f"[WARN] Reseller DB: {_e}")


@app.route("/api/internal/reseller_create", methods=["POST"])
def api_reseller_create():
    data = request.json or {}
    if data.get("bot_token") != BOT_TOKEN:
        return jsonify({"success": False, "error": "Unauthorized"}), 403
    discord_id  = str(data.get("discord_id", "")).strip()
    plan        = (data.get("plan", "starter") or "starter").lower()
    discord_tag = data.get("discord_tag", "")
    if not discord_id or plan not in RESELLER_PLANS_SERVER:
        return jsonify({"success": False, "error": "Paramètres invalides"})
    conn = get_db()
    existing = conn.execute("SELECT status FROM resellers WHERE discord_id=?", (discord_id,)).fetchone()
    if existing:
        conn.close()
        if existing["status"] == "active":
            return jsonify({"success": False, "error": "Tu es déjà revendeur actif."})
        if existing["status"] == "pending":
            return jsonify({"success": False, "error": "Demande déjà en attente."})
    try:
        conn.execute(
            "INSERT OR REPLACE INTO resellers (discord_id,discord_tag,plan,credits,status,joined_at) VALUES (?,?,?,0,'pending',?)",
            (discord_id, discord_tag, plan, int(time.time()))
        )
        conn.commit()
    except Exception as e:
        conn.rollback(); conn.close()
        return jsonify({"success": False, "error": str(e)})
    conn.close()
    add_log("OK", "RESELLER", f"Demande revendeur {plan} — {discord_tag}", discord_id)
    return jsonify({"success": True})


@app.route("/api/internal/reseller_approve", methods=["POST"])
def api_reseller_approve():
    data = request.json or {}
    if data.get("bot_token") != BOT_TOKEN:
        return jsonify({"success": False, "error": "Unauthorized"}), 403
    discord_id = str(data.get("discord_id", "")).strip()
    admin_by   = data.get("admin", "bot")
    conn = get_db()
    row = conn.execute("SELECT * FROM resellers WHERE discord_id=?", (discord_id,)).fetchone()
    if not row:
        conn.close(); return jsonify({"success": False, "error": "Revendeur introuvable"})
    plan   = row["plan"]
    rplan  = RESELLER_PLANS_SERVER.get(plan, RESELLER_PLANS_SERVER["starter"])
    credits = rplan["credits"]
    conn.execute(
        "UPDATE resellers SET status='active', credits=?, approved_by=?, joined_at=? WHERE discord_id=?",
        (credits, admin_by, int(time.time()), discord_id)
    )
    conn.execute(
        "INSERT INTO reseller_transactions (reseller_id,type,amount,credits_delta,note,admin,created_at) VALUES (?,?,?,?,?,?,?)",
        (discord_id, "activation", rplan["price"], credits, f"Activation plan {plan}", admin_by, int(time.time()))
    )
    conn.commit(); conn.close()
    add_log("OK", "RESELLER", f"Revendeur approuvé: {discord_id} plan={plan} crédits={credits}", admin_by)
    return jsonify({"success": True, "credits": credits, "plan": plan})


