@app.route("/api/internal/reseller_gen_keys", methods=["POST"])
def api_reseller_gen_keys():
    data = request.json or {}
    if data.get("bot_token") != BOT_TOKEN:
        return jsonify({"success": False, "error": "Unauthorized"}), 403
    discord_id = str(data.get("discord_id", "")).strip()
    plan       = (data.get("plan", "") or "").upper()
    qty        = max(1, min(int(data.get("qty", 1)), 20))
    if plan not in ("NORMAL", "PRO"):
        return jsonify({"success": False, "error": "Plan invalide"})
    conn = get_db()
    row = conn.execute("SELECT * FROM resellers WHERE discord_id=? AND status='active'", (discord_id,)).fetchone()
    if not row:
        conn.close(); return jsonify({"success": False, "error": "Tu n'es pas revendeur actif."})
    rplan    = RESELLER_PLANS_SERVER.get(row["plan"], RESELLER_PLANS_SERVER["starter"])
    discount = rplan["discount"]
    unit_cost = round(LICENSE_PRICES_SERVER[plan] * (1 - discount/100), 4)
    total_cost = round(unit_cost * qty, 2)
    if row["credits"] < total_cost:
        conn.close()
        return jsonify({"success": False, "error": f"Crédits insuffisants ({row['credits']:.2f} < {total_cost:.2f}€ requis)"})
    generated_keys = []
    try:
        for _ in range(qty):
            k = generate_key(plan)
            conn.execute("INSERT INTO licenses (key,plan,status,created_at) VALUES (?,?,?,?)",
                         (k, plan, "active", int(time.time())))
            conn.execute("INSERT INTO reseller_keys (reseller_id,license_key,plan,cost,status,created_at) VALUES (?,?,?,?,?,?)",
                         (discord_id, k, plan, unit_cost, "unused", int(time.time())))
            # Traçabilité : qui a généré cette clé
            conn.execute("INSERT INTO key_gen_log (license_key,plan,generated_by,gen_type,reseller_id,created_at) VALUES (?,?,?,?,?,?)",
                         (k, plan, discord_id, "reseller_api", discord_id, int(time.time())))
            generated_keys.append(k)
        new_credits = round(row["credits"] - total_cost, 4)
        conn.execute("UPDATE resellers SET credits=?, keys_generated=keys_generated+? WHERE discord_id=?",
                     (new_credits, qty, discord_id))
        conn.execute("INSERT INTO reseller_transactions (reseller_id,type,amount,credits_delta,note,created_at) VALUES (?,?,?,?,?,?)",
                     (discord_id, "gen_keys", total_cost, -total_cost, f"Génération {qty}x {plan}", int(time.time())))
        conn.commit()
    except Exception as e:
        conn.rollback(); conn.close()
        return jsonify({"success": False, "error": str(e)})
    conn.close()
    add_log("OK", "RESELLER", f"Revendeur {discord_id} génère {qty}x {plan} coût={total_cost}€", discord_id)
    return jsonify({"success": True, "keys": generated_keys, "cost": total_cost, "credits_left": new_credits, "discount": discount})


