    conn.execute("UPDATE resellers SET credits=? WHERE discord_id=?", (new_credits, discord_id))
    conn.execute("INSERT INTO reseller_transactions (reseller_id,type,amount,credits_delta,note,admin,created_at) VALUES (?,?,?,?,?,?,?)",
                 (discord_id, "recharge", credits, credits, note, admin_by, int(time.time())))
    conn.commit(); conn.close()
    add_log("OK", "RESELLER", f"Recharge {discord_id} +{credits} crédits par {admin_by}", admin_by)
    return jsonify({"success": True, "new_credits": new_credits})


