# ── Page admin revendeurs ──────────────────────────────────────────────────────
@app.route("/admin/resellers", methods=["GET","POST"])
@admin_required
def admin_resellers():
    msg = ""
    msg_type = "green"

    if request.method == "POST":
        action = request.form.get("action","")

        # ── Créer un accès admin pour un revendeur ──────────────────────────
        if action == "create_access":
            discord_id  = request.form.get("discord_id","").strip()
            username    = request.form.get("username","").strip().lower()
            password    = request.form.get("password","").strip()
            reseller_plan = request.form.get("reseller_plan","starter")
            if not discord_id or not username or not password:
                msg = "❌ Tous les champs sont requis."; msg_type = "red"
            else:
                conn = get_db()
                # Crée le revendeur dans resellers si pas déjà là
                existing_r = conn.execute("SELECT 1 FROM resellers WHERE discord_id=?", (discord_id,)).fetchone()
                if not existing_r:
                    rplan = RESELLER_PLANS_SERVER.get(reseller_plan, RESELLER_PLANS_SERVER["starter"])
                    conn.execute(
                        "INSERT OR IGNORE INTO resellers (discord_id,discord_tag,plan,credits,status,joined_at) VALUES (?,?,?,?,?,?)",
                        (discord_id, username, reseller_plan, rplan["credits"], "active", int(time.time()))
                    )
                # Crée le compte admin avec role=reseller
                existing_a = conn.execute("SELECT 1 FROM admins WHERE username=?", (username,)).fetchone()
                if existing_a:
                    msg = f"❌ Username '{username}' déjà utilisé."; msg_type = "red"
                else:
                    conn.execute(
                        "INSERT INTO admins (username,password_hash,role,reseller_id,created_at,created_by,active) VALUES (?,?,?,?,?,?,1)",
                        (username, _hash_password(password), "reseller", discord_id, int(time.time()), session["admin_user"])
                    )
                    conn.commit()
                    msg = f"✅ Accès revendeur créé : {username} / {password} → Discord ID {discord_id}"
                conn.commit(); conn.close()

        # ── Modifier le mot de passe ──────────────────────────────────────
        elif action == "reset_pw":
            username = request.form.get("username","").strip()
            new_pw   = request.form.get("new_pw","").strip()
            if username and new_pw:
                conn = get_db()
                conn.execute("UPDATE admins SET password_hash=? WHERE username=? AND role='reseller'",
                             (_hash_password(new_pw), username))
                conn.commit(); conn.close()
                msg = f"✅ Mot de passe mis à jour pour {username}"

        # ── Désactiver / réactiver ────────────────────────────────────────
        elif action == "toggle_access":
            username = request.form.get("username","").strip()
            conn = get_db()
            row = conn.execute("SELECT active FROM admins WHERE username=?", (username,)).fetchone()
            if row:
                new_v = 0 if row["active"] else 1
                conn.execute("UPDATE admins SET active=? WHERE username=?", (new_v, username))
                conn.commit()
                msg = f"{'✅ Accès activé' if new_v else '🔴 Accès désactivé'} : {username}"
            conn.close()

        # ── Supprimer l'accès ─────────────────────────────────────────────
        elif action == "delete_access":
            username = request.form.get("username","").strip()
            conn = get_db()
            conn.execute("DELETE FROM admins WHERE username=? AND role='reseller'", (username,))
            conn.commit(); conn.close()
            msg = f"🗑 Accès supprimé : {username}"

    conn = get_db()
    resellers = conn.execute("SELECT * FROM resellers ORDER BY joined_at DESC").fetchall()
    admin_accounts = conn.execute(
        "SELECT a.*, r.plan, r.credits, r.status as res_status, r.keys_generated "
        "FROM admins a LEFT JOIN resellers r ON a.reseller_id = r.discord_id "
        "WHERE a.role='reseller' ORDER BY a.created_at DESC"
    ).fetchall()
    total   = len(resellers)
    active  = sum(1 for r in resellers if r["status"] == "active")
    pending = sum(1 for r in resellers if r["status"] == "pending")
    revenue = sum(float(r["total_spent"] or 0) for r in resellers)
    conn.close()

