@app.route("/admin/resellers/<discord_id>/credit", methods=["POST"])
@admin_required
def admin_reseller_credit(discord_id):
    credits = float(request.form.get("credits", 0) or 0)
    if credits > 0:
        conn = get_db()
        conn.execute("UPDATE resellers SET credits=credits+? WHERE discord_id=?", (credits, discord_id))
        conn.execute("INSERT INTO reseller_transactions (reseller_id,type,amount,credits_delta,note,admin,created_at) VALUES (?,?,?,?,?,?,?)",
                     (discord_id, "recharge", credits, credits, "Recharge admin panel", session["admin_user"], int(time.time())))
        conn.commit(); conn.close()
        add_log("OK", "RESELLER", f"Recharge manuelle {discord_id} +{credits}", session["admin_user"])
    return redirect("/admin/resellers")


@app.route("/admin/resellers/<discord_id>/toggle", methods=["POST"])
@admin_required
def admin_reseller_toggle(discord_id):
    conn = get_db()
    row = conn.execute("SELECT status FROM resellers WHERE discord_id=?", (discord_id,)).fetchone()
    if row:
        new_s = "suspended" if row["status"] == "active" else "active"
        conn.execute("UPDATE resellers SET status=? WHERE discord_id=?", (new_s, discord_id))
        conn.commit()
    conn.close()
    return redirect("/admin/resellers")


@app.route("/api/internal/create_promo", methods=["POST"])
def api_create_promo():
    data = request.json or {}
    if data.get("bot_token") != BOT_TOKEN:
        return jsonify({"success": False, "error": "Unauthorized"}), 403
    code     = (data.get("code","") or "").upper().strip()
    reduction= int(data.get("reduction", 10))
    plan     = (data.get("plan","ALL") or "ALL").upper()
    max_uses = int(data.get("max_uses", 0))
    by       = data.get("created_by","bot")
    if not code:
        return jsonify({"success": False, "error": "Code vide"})
    try:
        conn = get_db()
        conn.execute("INSERT INTO promo_codes (code,reduction,plan,max_uses,created_by,created_at) VALUES (?,?,?,?,?,?)",
                     (code, reduction, plan, max_uses, by, int(time.time())))
        conn.commit(); conn.close()
        return jsonify({"success": True})
    except Exception as e:
        return jsonify({"success": False, "error": str(e)})

@app.route("/api/internal/search_user")
def api_search_user():
    if request.args.get("bot_token") != BOT_TOKEN:
        return jsonify({"error": "Unauthorized"}), 403
    query = (request.args.get("query","") or "").strip()
    conn  = get_db()
    results = []
    # Par username
    r = conn.execute("SELECT * FROM users WHERE username=?", (query.lower(),)).fetchone()
    if r:
        results.append(dict(r))
    # Par licence
    if not results:
        r = conn.execute("SELECT * FROM users WHERE license_key=?", (query.upper(),)).fetchone()
        if r:
            results.append(dict(r))
    # Par Discord ID
    if not results:
        rows = conn.execute("SELECT * FROM users WHERE discord_id=?", (query,)).fetchall()
        results.extend(dict(row) for row in rows)
    # Par IP
    if not results:
        rows = conn.execute("SELECT * FROM users WHERE ip=?", (query,)).fetchall()
        results.extend(dict(row) for row in rows)
    # Par N° commande
    if not results:
        order = conn.execute("SELECT * FROM shop_orders WHERE order_id=?", (query.upper(),)).fetchone()
        if order and order["username"]:
            r = conn.execute("SELECT * FROM users WHERE username=?", (order["username"],)).fetchone()
            if r:
                o_dict = dict(r)
                o_dict["order_id"] = order["order_id"]
                results.append(o_dict)
    conn.close()
    # Masquer les mots de passe
    for u in results:
        u.pop("password_hash", None)
        u.pop("temp_password", None)
    return jsonify(results if results else {"error": "Introuvable"})

