@app.route("/admin/site/product/create", methods=["POST"])
@admin_required
def admin_product_create():
    plan_new  = request.form.get("plan","NORMAL")
    price_new = float(request.form.get("price",4.99) or 4.99)
    conn = get_db()
    conn.execute("INSERT INTO site_products (plan,name,price,description,features,badge,active,sort_order) VALUES (?,?,?,?,?,?,?,?)",
        (plan_new, request.form.get("name",""),
         price_new,
         request.form.get("description",""), request.form.get("features","").replace("\n","|"),
         request.form.get("badge",""), int(request.form.get("active",1) or 1),
         int(request.form.get("sort_order",1) or 1)))
    conn.commit(); conn.close()
    pk = "price_pro" if plan_new == "PRO" else "price_normal"
    set_site_setting(pk, str(price_new))
    SHOP_PRICES["PRO" if plan_new=="PRO" else "NORMAL"]["price"] = price_new
    return redirect("/admin/site?tab=products")

@app.route("/admin/site/product/<int:pid>/edit", methods=["POST"])
@admin_required
def admin_product_edit(pid):
    new_price = float(request.form.get("price",4.99) or 4.99)
    conn = get_db()
    conn.execute("UPDATE site_products SET name=?,price=?,description=?,features=?,badge=?,active=? WHERE id=?",
        (request.form.get("name",""),
         new_price,
         request.form.get("description",""),
         request.form.get("features","").replace("\n","|"),
         request.form.get("badge",""),
         int(request.form.get("active",1) or 1),
         pid))
    conn.commit()
    # Sync price_normal / price_pro in site_settings so /pricing reflects change
    prod = conn.execute("SELECT plan FROM site_products WHERE id=?", (pid,)).fetchone()
    if prod:
        plan_key = "price_pro" if prod["plan"] == "PRO" else "price_normal"
        conn.close()
        set_site_setting(plan_key, str(new_price))
        SHOP_PRICES["PRO" if plan_key=="price_pro" else "NORMAL"]["price"] = new_price
    else:
        conn.close()
    add_log("OK","ADMIN",f"Produit {pid} prix={new_price:.2f}€", session["admin_user"])
    return redirect("/admin/site?tab=products")

