def reseller_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        if not session.get("reseller_logged"):
            return redirect("/admin/login?next=reseller")
        conn = get_db()
        row = conn.execute(
            "SELECT status FROM resellers WHERE discord_id=?",
            (session.get("reseller_id"),)
        ).fetchone()
        conn.close()
        if not row or row["status"] != "active":
            session.clear()
            return redirect("/admin/login?suspended=1")
        return f(*args, **kwargs)
    return decorated


def _get_reseller():
    conn = get_db()
    row  = conn.execute(
        "SELECT * FROM resellers WHERE discord_id=?",
        (session.get("reseller_id"),)
    ).fetchone()
    conn.close()
    return dict(row) if row else {}


